def validate(args, output):
    target = args[0]
    if not isinstance(output, str):
        return False
    def pos(ch):
        idx = ord(ch) - ord('a')
        return idx // 5, idx % 5
    r, c = 0, 0
    typed = []
    for m in output:
        if m == 'U':
            r -= 1
        elif m == 'D':
            r += 1
        elif m == 'L':
            c -= 1
        elif m == 'R':
            c += 1
        elif m == '!':
            typed.append(chr(r * 5 + c + ord('a')))
        else:
            return False
        # must remain on a valid board cell at every step
        if r < 0 or c < 0 or c > 4:
            return False
        if r > 5:
            return False
        if r == 5 and c != 0:
            return False
    if ''.join(typed) != target:
        return False
    # minimality: total moves must equal the manhattan-optimal count
    cr, cc = 0, 0
    opt = 0
    for ch in target:
        tr, tc = pos(ch)
        opt += abs(tr - cr) + abs(tc - cc) + 1
        cr, cc = tr, tc
    return len(output) == opt

