function validate(args, output) {
    const target = args[0];
    if (typeof output !== 'string') return false;
    function pos(ch) {
        const idx = ch.charCodeAt(0) - 97;
        return [Math.floor(idx / 5), idx % 5];
    }
    let r = 0, c = 0;
    let typed = '';
    for (const m of output) {
        if (m === 'U') r -= 1;
        else if (m === 'D') r += 1;
        else if (m === 'L') c -= 1;
        else if (m === 'R') c += 1;
        else if (m === '!') typed += String.fromCharCode(r * 5 + c + 97);
        else return false;
        if (r < 0 || c < 0 || c > 4) return false;
        if (r > 5) return false;
        if (r === 5 && c !== 0) return false;
    }
    if (typed !== target) return false;
    let cr = 0, cc = 0, opt = 0;
    for (const ch of target) {
        const [tr, tc] = pos(ch);
        opt += Math.abs(tr - cr) + Math.abs(tc - cc) + 1;
        cr = tr; cc = tc;
    }
    return output.length === opt;
}

