class Solution:
    def alphabetBoardPath(self, target):
        def pos(ch):
            idx = ord(ch) - ord('a')
            return idx // 5, idx % 5
        r, c = 0, 0
        out = []
        for ch in target:
            tr, tc = pos(ch)
            # move up first, left first, then down, then right
            while r > tr:
                out.append('U'); r -= 1
            while c > tc:
                out.append('L'); c -= 1
            while r < tr:
                out.append('D'); r += 1
            while c < tc:
                out.append('R'); c += 1
            out.append('!')
        return ''.join(out)

