class Solution:
    def alphabetBoardPath(self, target):
        def pos(ch):
            idx = ord(ch) - ord('a')
            return divmod(idx, 5)
        r = c = 0
        res = []
        for ch in target:
            tr, tc = pos(ch)
            if tr < r:
                res.append('U' * (r - tr))
            if tc < c:
                res.append('L' * (c - tc))
            if tr > r:
                res.append('D' * (tr - r))
            if tc > c:
                res.append('R' * (tc - c))
            res.append('!')
            r, c = tr, tc
        return ''.join(res)

