var alphabetBoardPath = function(target) {
    const pos = (ch) => {
        const idx = ch.charCodeAt(0) - 97;
        return [Math.floor(idx / 5), idx % 5];
    };
    let r = 0, c = 0;
    const res = [];
    for (const ch of target) {
        const [tr, tc] = pos(ch);
        if (tr < r) res.push('U'.repeat(r - tr));
        if (tc < c) res.push('L'.repeat(c - tc));
        if (tr > r) res.push('D'.repeat(tr - r));
        if (tc > c) res.push('R'.repeat(tc - c));
        res.push('!');
        r = tr; c = tc;
    }
    return res.join('');
};
